    /**
     * @param string $type
     * @param Zend_Controller_Request_Abstract $request
     * @return Admin_Model_Address
     */
    public static function createAddress(string $type, Zend_Controller_Request_Abstract $request, int $userID = null, $main=true): Admin_Model_Address {
        $requestPrefix = '';
        if ($type == self::TYPE_DELIVERY)
            $requestPrefix = 'D';

        $address = new Admin_Model_Address();
        $address->Type = $type;
        $address->Main = $main;
        $address->User_ID = $userID??null;
        $address->Label = $request->getParam('Label');
        $address->FirstName = $request->getParam($requestPrefix . 'FirstName');
        $address->LastName = $request->getParam($requestPrefix . 'LastName');
        $address->Street = $request->getParam($requestPrefix . 'Street');
        $address->City = $request->getParam($requestPrefix . 'City');
        $address->ZipCode = $request->getParam($requestPrefix . 'ZipCode');
        $address->Email = $request->getParam('Email');
        $address->Phone = $request->getParam('Phone');
        $address->Country_ID = !empty($request->getParam($requestPrefix . 'Country'))?$request->getParam($requestPrefix . 'Country'):Country::CZ_ID;
        $address->CompanyName = $request->getParam( 'CompanyName');
        if ($type == self::TYPE_INVOICE) {
            $address->IC = $request->getParam('IC');
            $address->DIC = $request->getParam('DIC');
        }
        $address->save();

        return $address;
    }

