    /**
     * @param array $params
     */
    public static function updateCurrentUserAddress(array $params) {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Address object');
        $query->where('object.ID = ?', User::getCurrentUser()->InvoiceAddress_ID);

        /** @var Admin_Model_Address $address */
        $address = $query->fetchOne();
        if(!$address) {
            $address = new Admin_Model_Address();
            $address->save();
            $user = User::getCurrentUser();
            $user->InvoiceAddress_ID = $address->ID;
            $user->save();
        }

        if (isset($params['CompanyName']) && !empty($params['CompanyName']))
            $address->CompanyName = $params['CompanyName'];
        if (isset($params['FirstName']) && !empty($params['FirstName']))
            $address->FirstName = $params['FirstName'];
        if (isset($params['LastName']) && !empty($params['LastName']))
            $address->LastName = $params['LastName'];
        if (isset($params['Street']) && !empty($params['Street']))
            $address->Street = $params['Street'];
        if (isset($params['City']) && !empty($params['City']))
            $address->City = $params['City'];
        if (isset($params['ZipCode']) && !empty($params['ZipCode']))
            $address->ZipCode = $params['ZipCode'];
        if (isset($params['Phone']) && !empty($params['Phone']))
            $address->Phone = $params['Phone'];
        if (isset($params['IC']) && !empty($params['IC']))
            $address->IC = $params['IC'];
        if (isset($params['DIC']) && !empty($params['DIC']))
            $address->DIC = $params['DIC'];
        $address->save();
    }

