        if (!$address) {
            $address = new Admin_Model_Address();
        }

        $address->FirstName = $params['DFirstName'];
        $address->LastName = $params['DLastName'];
        $address->Street = $params['DStreet'];
        $address->City = $params['DCity'];
        $address->ZipCode = $params['DZipCode'];
        $address->save();

