        $newAddress->ZipCode = $address['ZipCode'];
        $newAddress->Email = $address['Email'];
        $newAddress->Phone = $address['Phone'];
        $newAddress->CompanyName = $address['CompanyName'];
        $newAddress->IC = $address['IC'];
        $newAddress->DIC = $address['DIC'];
        $newAddress->save();

