    public static function updateAddress(int $addressID, Zend_Controller_Request_Abstract $request, int $userID, bool $isDelivery): void {
        $address = self::getAddress($addressID);
        $requestPrefix = '';
        if($address->User_ID != $userID) {
            return;
        }

        //main je pouze u jednoho typu adresy
        if(filter_var($request->getParam('MainAddress'), FILTER_VALIDATE_BOOLEAN)) {
            self::clearMainAddress($userID, $isDelivery ? self::TYPE_DELIVERY : self::TYPE_INVOICE);
        }

        if ($isDelivery)
            $requestPrefix = 'D';

        if ($address) {
            $address->Label =  $request->getParam($requestPrefix . 'Label')??null;
            $address->FirstName = $request->getParam($requestPrefix . 'FirstName')??null;
            $address->LastName = $request->getParam($requestPrefix . 'LastName')??null;
            $address->Street = $request->getParam($requestPrefix . 'Street')??null;
            $address->City = $request->getParam($requestPrefix . 'City')??null;
            $address->ZipCode = $request->getParam($requestPrefix . 'ZipCode')??null;
            $address->Email  = $request->getParam('Email')??null;
            $address->Phone = $request->getParam('Phone')??null;
            $address->Main = filter_var($request->getParam('MainAddress'), FILTER_VALIDATE_BOOLEAN);
            $address->Country_ID = $request->getParam($requestPrefix . 'Country') ?? null;
            if ($isDelivery) {
                $address->save();
            } else {
                $address->CompanyName =$request->getParam('CompanyName');
                $address->IC = $request->getParam('IC');
                $address->DIC = $request->getParam('DIC');
                $address->save();
            }
        }
    }

    public static function clearMainAddress(?int $userID, string $type) {
        $query = Doctrine_Query::create();
        $query->update('Admin_Model_Address object');
        $query->set('object.Main', 0);
        $query->where('object.User_ID = ?', $userID);
        $query->andWhere('object.Type = ?', $type);
        $query->execute();
    }

    public static function deleteAddress(int $userID, int $addressID): void {
        $query = Doctrine_Query::create();
        $query->delete('Admin_Model_Address object');
        $query->where('object.ID = ?', $addressID);
        $query->andWhere('object.User_ID = ?', $userID);
        $query->execute();
    }

    public static function createAddressFromOldAccount(string $type, OldUser $oldUser, int $newUserID): ?Admin_Model_Address {

        if ($type == self::TYPE_INVOICE) {
            $name = explode(' ', $oldUser->ContactPerson);
            if ($oldUser->CompanyCountry == 'ČR') {
                $countryID = Common_Model_Country::CZ_ID;
            }
            if ($oldUser->CompanyCountry == 'SR') {
                $countryID = Common_Model_Country::SK_ID;
            }
            $address = new Admin_Model_Address();
            $address->Type = $type;
            $address->FirstName = end($name);
            $address->LastName =  $name[0];
            $address->Street = $oldUser->CompanyStreet;
            $address->City = $oldUser->CompanyCity;
            $address->ZipCode = $oldUser->CompanyZipCode;
            $address->IC = $oldUser->CompanyID;
            $address->DIC = $oldUser->CompanyVatID;
            $address->Email = $oldUser->ContactEmail;
            $address->Phone = $oldUser->ContactPhone;
            $address->CompanyName = $oldUser->CompanyName;
            $address->User_ID = $newUserID;
            if ($countryID) {
                $address->Country_ID = $countryID;
            }
            $address->Main = 1;
            $address->save();

        } else {
            $name = explode(' ', $oldUser->ContactPerson);
            if ($oldUser->DeliveryCountry == 'ČR') {
                $countryID = Common_Model_Country::CZ_ID;
            }
            if ($oldUser->DeliveryCountry == 'SR') {
                $countryID = Common_Model_Country::SK_ID;
            }
            $address = new Admin_Model_Address();
            $address->Type = $type;
            $address->FirstName = $name[0];
            $address->LastName = end($name);
            $address->Street = $oldUser->DeliveryStreet;
            $address->City = $oldUser->DeliveryCity;
            $address->ZipCode = $oldUser->DeliveryZipCode;
            $address->Email = $oldUser->ContactEmail;
            $address->Phone = $oldUser->ContactPhone;
            $address->CompanyName = $oldUser->DeliveryName;
            $address->User_ID = $newUserID;
            if ($countryID) {
                $address->Country_ID = $countryID;
            }
            $address->Main = 1;
            $address->save();
        }

        return $address;

    }

    /**
     * Vrací celé jméno
     * @return string
     */
    public function getFullName(): string {
        $fullName = '';

        if (!empty($this->FirstName))
            $fullName = $this->FirstName;

        if (!empty($this->LastName)) {
            if (!empty($fullName))
                $fullName .= ' ';

            $fullName .= $this->LastName;
        }

        return $fullName;
    }

    /**
     * Vrací celou ulici s ČP
     * @return string
     */
    public function getFullStreet(): string {
        $street = '';

        if (!empty($this->Street))
            $street = $this->Street;

        return $street;
    }

    /**
     * Vrací město s PSČ
     * @return string
     */
    public function getFullCity(): string {
        $city = '';

        if (!empty($this->City))
            $city = $this->City;

        if (!empty($this->ZipCode)) {
            if (!empty($city))
                $city .= ' ';

            $city .= $this->ZipCode;
        }

        return $city;
    }

    /**
     * Vrací číslo
     * @param bool $withoutSpace
     * @return string
     */
    public function getPhone($withoutSpace = false): string {
        $phone = '';

        if (!empty($this->PhonePrefix))
            $phone = $this->PhonePrefix;

        if (!empty($this->Phone)) {
            if (!empty($phone) && !$withoutSpace)
                $phone .= ' ';

            $phone .= $this->Phone;
        }

        return $phone;
    }

    /**
     * Vrací název státu
     * @return string
     * @throws Exception
     */
    public function getCountryCode(): string {
        return $this->Country_ID ? $this->country->Code2 : 'CZ';
    }
